#### 2. `board.py` - Represents the checkers board.

```python
class Board:
    def __init__(self):
        self.board = [[None] * 8 for _ in range(8)]
        self.initialize_board()

    def initialize_board(self):
        for row in range(3):
            for col in (1, 3, 5, 7):
                if (row + col) % 2 == 0:
                    self.board[row][col] = Piece("red", "normal")
        for row in range(5, 8):
            for col in (0, 2, 4, 6):
                if (row + col) % 2 == 0:
                    self.board[row][col] = Piece("black", "normal")

    def display(self):
        for row in self.board:
            print(' '.join(f"{piece.symbol if piece else '.'}" for piece in row))

class Piece:
    def __init__(self, color, type="normal"):
        self.color = color
        self.type = type

    @property
    def symbol(self):
        if self.color == "red":
            return 'R' if self.type == "king" else 'r'
        elif self.color == "black":
            return 'B' if self.type == "king" else 'b'
        return '.'
```

